const togglePassword = () => {
    const toggleBtn = document.querySelectorAll('[data-toggle-pass]');

    if(toggleBtn.length) {
        toggleBtn.forEach(el => {
            el.addEventListener('click', function () {
                if(this.previousElementSibling.type === 'password') {
                    this.previousElementSibling.type = 'text'
                    this.innerHTML = `<svg><use href="#eye-open"/></svg>`
                } else {
                    this.previousElementSibling.type = 'password'
                    this.innerHTML = `<svg><use href="#eye-closed"/></svg>`
                }
            })
        })
    }

    const inputPass = document.querySelectorAll('[data-password]')
    if(inputPass.length) {
        inputPass.forEach(el => {
            el.addEventListener('focus', function () {
                const note = this.closest('.form__col').querySelector('.password-note')
                if(note) {
                    note.style.display = 'block'
                }
            })
        })
    }
}

export default togglePassword;