import {parseJSON} from './utils/parseJSON';
import {render} from './utils/render';

const loadMoreBlock = '[data-load-more-block]';
const loadMoreBtn = '[data-load-more-btn]';

export default class LoadMore {
    constructor() {
        this.loadMoreBlock = document.querySelectorAll(loadMoreBlock);
        this.loadMoreBtn = document.querySelectorAll(loadMoreBtn);

        this.paginationNumber = 2;

        this.bindEvents();
    }

    loadContent(btn) {
        let params = btn.dataset.loadMoreBtn;
        params = parseJSON(params);

        let url = params.url;


        if (params.urlDebug) {
            url = params.urlDebug;
        } else {
            url = url.split('=');
            const urlText = url[0] + '=';
            let urlNum = this.paginationNumber.toString();
            url = urlText + urlNum;
        }

        params.url = url;
        btn.dataset.loadMoreBtn = JSON.stringify(params);

        fetch(params.url)
            .then(res => params.urlDebug ? res.text() : res.json())
            .then(data => {
                let { html } = data;

                if (params.urlDebug) { // если тянем моковые данные
                    html = data;
                }

                this.paginationNumber += 1;
                render(btn, html, 'beforebegin');

                if (data.isEnd) {
                    btn.style.display = 'none';
                }

                if (!data.isEnd && params.urlDebug) { // ТОЛЬКО для моковых данных
                    btn.style.display = 'none';
                }
            })
            .catch((e) => {
                console.error('Error: ' + e.message);
                console.error(e.response);
            });
    }

    bindEvents() {
        this.loadMoreBtn.forEach((btn) => {
            btn.addEventListener('click', (e) => {
                e.preventDefault();
                this.loadContent(e.target);
            });
        });
    }
}