import Collection from './generic/collection'
import { Swiper, Navigation, Pagination, Autoplay } from 'swiper/dist/js/swiper.esm.js'
import 'swiper/dist/css/swiper.min.css'

Swiper.use([Navigation, Pagination, Autoplay]);

/**
 * Класс для коллекции слайдеров.
 * Элемент коллекции можно получить при помощи метода getByDOMElement
 */
export default class Sliders extends Collection {
    sliders = [
        {
            'selector': '.slider-promo',
            'options': {
                slidesPerView: 1,
                pagination: {
                    el: '.slider-pagination',
                    clickable: true,
                },
                speed: 700,
                autoplay: {
                    delay: 5000,
                    disableOnInteraction: true,
                    pauseOnMouseEnter: true
                },
                loop: true
            }
        },
        {
            'selector': '[data-slider-articles]',
            'options': {
                slidesPerView: 3,
                spaceBetween: 0,
                navigation: {
                    nextEl: '[data-slider-articles] .swiper-button-next',
                    prevEl: '[data-slider-articles] .swiper-button-prev',
                },
                pagination: {
                    el: '[data-slider-articles] .swiper-pagination',
                    type: 'progressbar',
                },
                breakpoints: {
                    920: {
                        slidesPerView: 2,
                    },
                    620: {
                        slidesPerView: 'auto',
                    }
                },
                speed: 700,
                watchOverflow: true,
                autoHeight: true
            }
        },
        {
            'selector': '.docs-slider .swiper-container',
            'options': {
                slidesPerView: 3,
                spaceBetween: 20,
                navigation: {
                    nextEl: '.docs-slider .swiper-button-next',
                    prevEl: '.docs-slider .swiper-button-prev',
                },
                pagination: {
                    el: '.docs-slider .swiper-pagination',
                    type: 'progressbar',
                },
                breakpoints: {
                    1170: {
                        slidesPerView: 4,
                    },
                    600: {
                        slidesPerView: 2,
                    }
                }
            }
        }
    ];

    constructor() {
        super();
        this.init();
    }

    init() {
        this.sliders.forEach(slider => {
            const sliders = document.querySelectorAll(slider.selector);

            for (let sliderDOMElem of sliders) {
                const swiperSlider = new Slider(sliderDOMElem, slider.options);
                this.collection = swiperSlider;
            }
        });
    }
}

export class Slider {
    instance;
    swiperInstance;

    /**
     *
     * @param sliderDOMElem{HTMLElement}
     * @param options{Object}
     * @return {Class}
     */
    constructor(sliderDOMElem, options) {
        this.instance = sliderDOMElem;
        this.swiperInstance = new Swiper(sliderDOMElem, options);
    }
}
