import {render} from './utils/render.js';

const searchForm = '[data-search-form]';
const searchInput = '[data-search-input]';

export default class Search {
    constructor() {
        this.searchForm = document.querySelector(searchForm);
        this.searchInput = document.querySelector(searchInput);

        this.bindEvents();
    }

    getResult(form) {
        const formData = new URLSearchParams(new FormData(form)).toString();
        const dataOptions = JSON.parse(form.dataset.searchForm);
        
        const {url, content, isDebug} = dataOptions;
        const contentPlace = document.querySelector(content);

        const options = {
            method: 'post',
            body: formData,
            headers: {
                'Bx-ajax': 'true',
                'X-Requested-With': 'XMLHttpRequest',
                'content-type': 'application/x-www-form-urlencoded'
            },
        }; 

        fetch(url, options)
            .then(res => res.text())
            .then(res => {
                contentPlace.innerHTML = '';
                render(contentPlace, res);
                //выполняем скрипты, которые есть в компонентах на странице
                let processed = BX.processHTML(res, false);
                BX.ajax.processScripts(processed.SCRIPT);
            });
    }

    bindEvents() {
        if (this.searchForm) {
            this.searchForm.addEventListener('submit', (e) => {
                e.preventDefault();
                this.getResult(e.target);
            });
        }
    }
}