import IMask from 'imask';

import 'pickmeup/css/pickmeup.css'
import pickmeup from 'pickmeup';

const instance = '[data-input-date]';

export default class DateCalendar {
    constructor() {
        this.instance = document.querySelectorAll(instance);

        this.init();
        this.bindEvents();
    }

    setDefault() {
        pickmeup.defaults.locales['ru'] = {
            days: ['Воскресенье', 'Понедельник', 'Вторник', 'Среда', 'Четверг', 'Пятница', 'Суббота'],
            daysShort: ['Вс', 'Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб'],
            daysMin: ['Вс', 'Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб'],
            months: ['Январь', 'Февраль', 'Март', 'Апрель', 'Май', 'Июнь', 'Июль', 'Август', 'Сентябрь', 'Октябрь', 'Ноябрь', 'Декабрь'],
            monthsShort: ['Янв', 'Фев', 'Мар', 'Апр', 'Май', 'Июн', 'Июл', 'Авг', 'Сен', 'Окт', 'Ноя', 'Дек']
        };
    }

    setMask(dateInput) {
        const dateMask = IMask(dateInput, {
            mask: Date,
        });

        return dateMask;
    }

    init(dateInputs) {
        dateInputs = dateInputs || this.instance;

        this.setDefault();

        dateInputs.forEach((it) => {
            const isOnlyMonth = typeof it.dataset.inputDateOnlyMonth !== 'undefined';
            this.setMask(it);

            pickmeup(it, {
                format: isOnlyMonth ? 'B Y' : it.dataset.inputDate,
                locale: 'ru',
                separator: '.',
                select_day: isOnlyMonth ? false : true,
                default_date: false
            });

            it.classList.add('date-initialized');
        });
    }

    bindEvents(dateInputs) {
        dateInputs = dateInputs || this.instance;

        dateInputs.forEach((it) => {
            it.addEventListener('pickmeup-change', () => {
                pickmeup(it).hide();
            });
        });
    }
}