import {render} from './utils/render.js';

const instance = '[data-video-time]';
const instanceMinutes = '[data-video-time-min]';
const instanceSeconds = '[data-video-time-sec]';

const instanceMinutesZero = '[data-video-time-min-zero]';
const instanceSecondsZero = '[data-video-time-sec-zero]';

export default class VideoLibraryTime {
    constructor() {
        this.instance = document.querySelectorAll(instance);
        this.instanceMinutes = document.querySelectorAll(instanceMinutes);
        this.instanceSeconds = document.querySelectorAll(instanceSeconds);

        this.instanceMinutesZero = document.querySelectorAll(instanceMinutesZero);
        this.instanceSecondsZero = document.querySelectorAll(instanceSecondsZero);

        this.minutesBorder = 5;
        this.isFiveMinutesLeft = false;

        this.getResult();
    }

    renderTime(htmlLayout, val) {
        htmlLayout.forEach((it) => {
            render(it, val)
        });
    }

    setStartLayout(minutes, seconds) {
        this.renderTime(this.instanceMinutes, minutes);
        this.renderTime(this.instanceSeconds, seconds);
    }

    setInnerHTML(htmlLayout, val) {
        htmlLayout.forEach((it) => {
            it.innerHTML = val;
        });
    }

    setZeroForTime(zeroLayout, time) {
        if (time < 10) {
            this.setInnerHTML(zeroLayout, '0');
        } else {
            this.setInnerHTML(zeroLayout, '');
        }
    }

    setTime(time, modal) {
        let { minutes, seconds } = time;

        minutes = Number(minutes);
        seconds = Number(seconds);

        this.setStartLayout(minutes, seconds);

        this.setZeroForTime(this.instanceSecondsZero, seconds);
        this.setZeroForTime(this.instanceMinutesZero, minutes);
        
        window.setInterval(() => {
            seconds -= 1;

            if (seconds < 0) {
                seconds = 60;
                minutes -= 1;

                this.setInnerHTML(this.instanceMinutes, '');
                this.renderTime(this.instanceMinutes, minutes);
            }

            this.setZeroForTime(this.instanceSecondsZero, seconds);
            this.setZeroForTime(this.instanceMinutesZero, minutes);

            if (minutes < this.minutesBorder) { // если текущее кол-во минут меньше лимит (сейчас 5)
                if (!this.isFiveMinutesLeft) {
                    this.isFiveMinutesLeft = true;

                    App.Modals.open(modal);
                }
            }

            if (minutes < 0) {
                // Здесь должна быть логика, при которой у пользователя закончилось время доступа к видеотеке
                let href = window.location.href;
                window.location.replace(href);

                this.instance.forEach((instance) => {
                    instance.style.display = 'none';
                });
            }

            this.setInnerHTML(this.instanceSeconds, '');
            this.renderTime(this.instanceSeconds, seconds);
        }, 1000)
    }

    getResult() {
        if (this.instance[0]) {
            const { url, modal } = JSON.parse(this.instance[0].dataset.videoTime);

            fetch(url)
                .then(res => res.json())
                .then((res) => {
                    const time = res.time;

                    this.setTime(time, modal);
                });
        }
    }
} 