export default class NavArticle {
  els = {
    link: '[data-article-nav]',
  };

  constructor() {
    this.navElements = document.querySelectorAll(this.els.link);
    this.events();
  }

  scrollToBlock(elem) {
    elem.scrollIntoView({ block: 'start', behavior: 'smooth' });
  }

  events() {
    this.navElements.forEach((item) => {
      item.addEventListener('click', (e) => {
        e.preventDefault();
        const href = item.href.split('#')[1];
        const element = document.querySelector(`#${href}`);
        if (element) {
          this.scrollToBlock(element);
        }
      });
    });
  }
}
