import Vue from 'vue';
import features from './features';
import 'vue-select/dist/vue-select.css';

const valueDescriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value');

function initAndPatchDateInput(input) {
  if (input._datePatchApplied) return;
  input._datePatchApplied = true;
  Object.defineProperty(input, 'value', {
    get() { return valueDescriptor.get.call(this); },
    set(val) {
      valueDescriptor.set.call(this, val);
      this.dispatchEvent(new Event('input', { bubbles: true }));
    },
  });
  if (window.App?.DateCalendar) {
    App.DateCalendar.init([input]);
    App.DateCalendar.bindEvents([input]);
  }
}

const dateInputObserver = new MutationObserver((mutations) => {
  mutations.forEach((mutation) => {
    mutation.addedNodes.forEach((node) => {
      if (node.nodeType !== Node.ELEMENT_NODE) return;
      if (node.matches?.('[data-input-date]')) initAndPatchDateInput(node);
      node.querySelectorAll?.('[data-input-date]').forEach(initAndPatchDateInput);
    });
  });
});

document.addEventListener('DOMContentLoaded', () => {
  dateInputObserver.observe(document.body, { childList: true, subtree: true });
  Object.keys(features).forEach((selector) => {
    const el = document.querySelector(selector);
    if (el) {
      new Vue({
        el: el,
        render: (h) => h(features[selector]),
      });
    }
  });
});
