import { lock, unlock } from 'tua-body-scroll-lock'

export default class Menu {
    constructor() {
        this.menu = document.querySelector('[data-menu]');
        this.menuOverlay = document.querySelector('[data-menu-overlay]');
        this.menuScrollable = document.querySelector('[data-menu-scrollable]');
        this.menuBtnOpen = document.querySelector('[data-menu-btn-open]');
        this.menuBtnClose = document.querySelector('[data-menu-btn-close]');		

        this.isMenuOpened = false;

        this.bindEvents();
    }

    openMenu() {
        this.menu.classList.add('active');
        lock(this.menuScrollable);
        this.isMenuOpened = true;
    }

    closeMenu() {
        this.menu.classList.remove('active');
        unlock(this.menuScrollable);
        this.isMenuOpened = false;
    }

    bindEvents() {
        this.menuBtnOpen.addEventListener('click', () => this.openMenu());
        this.menuBtnClose.addEventListener('click', () => this.closeMenu());
        this.menuOverlay.addEventListener('click', () => this.closeMenu());
    }
}