/*eslint-disable*/
function toggleForms () {
    const toggleBlock = document.querySelectorAll('.toggle');
    const stateForms = {
        person: 'private_person',
        organization: 'organization'
    }
    if (toggleBlock.length) {
        toggleBlock.forEach(el => {
            el.addEventListener('click', function (event) {
                const target = event.target;
                const state = el.dataset.selectForm;

                if (target.closest('.toggle__link')) {
                    const link = target.dataset.tabsLink
                    if(state !== link) {
                        el.dataset.selectForm = link;
                    }
                }

                let btn = target.closest('.toggle-bg');
                if(btn) {
                    state === stateForms.person ?
                      el.dataset.selectForm = stateForms.organization :
                      el.dataset.selectForm = stateForms.person;

                    let parent = btn.closest('.toggle');
                    if (parent) {
                        let eventClick = $.Event('click');
                        eventClick.target = parent.querySelector('.toggle__link:not(.is-active)');
                        $(parent).trigger(eventClick);
                    }
                }
            });
        });
    }
}

export default toggleForms;