import './vue/main';

function requireAll(r) {
  r.keys().forEach(r);
}

requireAll(require.context('./icons', true, /\.svg$/));

import './js/polyfills';

// Load plugins
import 'jquery';
import IMask from 'imask';

import './js/plugins';

import svg4everybody from 'svg4everybody';
window.svg4everybody = svg4everybody;

import objectFitImages from 'object-fit-images';
window.objectFitImages = objectFitImages;

import imagesLoaded from 'imagesloaded';
window.imagesLoaded = imagesLoaded;

// load modules
import Utils from './js/utils/utils';
import SvgUse from './js/svgUse';
import Tabs from './js/tabs';
import Sliders from './js/sliders';
import Modals from './js/modals';
import Forms from './js/forms/forms';

import Menu from './js/menu';
import Search from './js/search';
import Gallery from './js/gallery';
import VideoLibraryTime from './js/video-library-time';
import DateCalendar from './js/date-calendar';
import Details from './js/details';
import NavArticle from './js/nav-article';
import togglePassword from './js/togglePassword';
window.togglePassword = togglePassword;
import showLoginForm from './js/showLoginForm';
import LoadMore from './js/loadMore';
import replacingButtons from './js/replacingButtons';
import toggleForms from './js/forms/toggleForms';
window.toggleForms = toggleForms;
import VSelect from './js/v-select';
// Load components

// import ExampleComponent from "./components/_example";
import './components/breadcrumbs';
import './components/pagination';

// Load styles
import './styles/app.js';
import './styles/tailwind.css';

// Run components

window.App = {
  lang: 'ru',
};

if (window.SITE_LANG) {
  App.lang = window.SITE_LANG;
}

document.addEventListener('DOMContentLoaded', function () {
  objectFitImages();

  App.Utils = new Utils();
  App.Forms = new Forms();
  App.SvgUse = new SvgUse();
  App.Sliders = new Sliders();
  App.Tabs = new Tabs();
  App.Modals = new Modals();

  App.Menu = new Menu();
  App.Search = new Search();
  App.Gallery = new Gallery();
  App.VideoLibraryTime = new VideoLibraryTime();
  App.DateCalendar = new DateCalendar();
  // App.FormConstructor = new FormConstructor();
  App.Details = new Details();
  App.NavArticle = new NavArticle();
  App.LoadMore = new LoadMore();

  togglePassword();
  showLoginForm();
  replacingButtons();
  toggleForms();

  $('.inputmask').each(function () {
    IMask($(this)[0], { mask: '+{7} (000) 000-0000' });
  });

  $('[data-input-mask-only-numbers]').each(function () {
    IMask($(this)[0], {
      mask: Number,
    });
  });

  // prevent copying

  $('.no-select').on('selectstart', false);

  $('.no-select img').on('mousedown', false);
});
