const detailsNoOpen = '[data-details-no-open]';
const detailsCustom = '[data-custom-details]';
const detailsCustomPopup = '[data-custom-details-popup]';
const detailsCustomAccordionBtn = '[data-custom-details-accordion-btn]';

export default class Details {
  constructor() {
    this.detailsNoOpen = document.querySelectorAll(detailsNoOpen);
    this.detailsCustom = document.querySelectorAll(detailsCustom);
    this.detailsCustomAccordionBtn = document.querySelectorAll(detailsCustomAccordionBtn);

    this.bindEvents();
  }

  bindEvents() {
    this.detailsNoOpen.forEach((detail) => {
      detail.addEventListener('click', (e) => {
        e.preventDefault();
      });
    });

    this.detailsCustom.forEach((detail) => {
      detail.addEventListener('click', (e) => {
        if (e.target.className !== 'table__act' && e.target.className !== 'table__col-name') {
          detail.classList.toggle('open');
        }
      });
    });

    this.detailsCustomAccordionBtn.forEach((detailBtn) => {
      detailBtn.addEventListener('click', () => {
        detailBtn.closest(detailsCustomPopup).classList.toggle('open');
      });
    });
  }
}
